form:Form.form:Scripts:
		function OnLoad()
{
	Ctrl("reportShow").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file=NucleusWF.Base.Ejecucion.WaitProcess.rpt&oi_instance="+Ctrl("oi_instance").GetXValue()+"&amp;crc="+Ctrl('crc').GetXValue());
}

function FinishWait(oi_thread, oi_node)
{
	Ctrl("oi_thread").SetXValue(oi_thread);
	Ctrl("oi_node").SetXValue(oi_node);
	Ctrl("main").DoEvent("FINISH-WAIT");
}
